// Format top 5 topics into daily digest email
const data = $input.all()[0].json;
const topics = (data.topics || []).slice(0, 5);

// Build email HTML
let html = '<div style="font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto;">';
html += '<div style="background: linear-gradient(135deg, #11998e 0%, #38ef7d 100%); color: white; padding: 30px; text-align: center; border-radius: 10px 10px 0 0;">';
html += '<h1 style="margin: 0;">📊 Today on DoubtMap</h1>';
html += '</div>';

html += '<div style="background: #f9f9f9; padding: 30px; border-radius: 0 0 10px 10px;">';
html += '<p style="font-size: 16px; color: #333;">Here are the <strong>hottest topics</strong> your classmates are asking about:</p>';

html += '<ol style="padding-left: 20px;">';

for (const t of topics) {
  const confidence = t.avg_confidence || t.confidence || 0;
  const emoji = confidence < 0.6 ? '🔴' : confidence < 0.8 ? '🟡' : '🟢';
  const confidencePercent = (confidence * 100).toFixed(0);

  html += '<li style="margin: 15px 0; padding: 15px; background: white; border-radius: 8px; border-left: 4px solid #11998e;">';
  html += `<strong style="color: #11998e; font-size: 18px;">${emoji} ${t.topic || 'Unknown Topic'}</strong><br>`;
  html += `<span style="color: #666; font-size: 14px;">${t.count || 0} doubts asked</span>`;
  html += ` | <span style="color: #666; font-size: 14px;">Avg confidence: ${confidencePercent}%</span>`;
  html += '</li>';
}

html += '</ol>';

html += '<div style="background: #e8f5e9; padding: 15px; border-radius: 8px; margin: 20px 0;">';
html += '<p style="margin: 0; color: #2e7d32; font-size: 14px;">💡 <strong>Legend:</strong> 🟢 High confidence | 🟡 Medium confidence | 🔴 Needs professor help</p>';
html += '</div>';

html += '<div style="text-align: center; margin: 30px 0;">';
html += '<a href="http://localhost:3000/student/chat" style="display: inline-block; background: #11998e; color: white; padding: 12px 30px; text-decoration: none; border-radius: 5px; font-weight: bold;">Ask Your Own Doubts →</a>';
html += '</div>';

html += '<p style="color: #666; font-size: 14px; text-align: center;">Stay curious and keep learning! 🚀</p>';
html += '</div>';

html += '<div style="text-align: center; margin-top: 20px; color: #999; font-size: 12px;">';
html += '<p>~ The DoubtMap Team</p>';
html += '<p>You are receiving this daily digest because you are an active DoubtMap user.</p>';
html += '</div>';
html += '</div>';

return [{
  json: {
    emailBody: html,
    topicCount: topics.length,
    student_emails: 'students@example.com'
  }
}];
